import React, { useState, useEffect, useRef } from "react";
import io from "socket.io-client";

const ChatSocket = ({ goBack }) => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [socket, setSocket] = useState(null);
  const [isConnected, setIsConnected] = useState(false);
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [friends, setFriends] = useState([]);
  const [selectedFriend, setSelectedFriend] = useState(null);
  const [privateMessages, setPrivateMessages] = useState({});
  const [chatMode, setChatMode] = useState('public'); // 'public' or 'private'
  const [selectedImage, setSelectedImage] = useState(null);
  const [notifications, setNotifications] = useState([]);
  const messagesEndRef = useRef(null);
  const fileInputRef = useRef(null);
  const cameraInputRef = useRef(null);
  const friendsFetchedRef = useRef(false);

  // Lấy token từ localStorage
  const getToken = () => localStorage.getItem('token');

  const currentUserId = JSON.parse(atob(getToken().split('.')[1])).id;

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, privateMessages]);

  // Fetch danh sách bạn bè
  const fetchFriends = async () => {
    try {
      const token = getToken();
      if (!token) return;

      const response = await fetch('http://localhost:3001/api/friends', {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (response.ok) {
        const data = await response.json();
        setFriends(data.friends || []);
      }
    } catch (err) {
      console.error('Error fetching friends:', err);
    }
  };

  // Fetch tin nhắn cá nhân với friend
  const fetchPrivateMessages = async (friendId) => {
    try {
      const token = getToken();
      if (!token) return;

      const response = await fetch(`http://localhost:3001/api/private-messages/${friendId}`, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (response.ok) {
        const data = await response.json();
        setPrivateMessages(prev => ({
          ...prev,
          [friendId]: data.messages || []
        }));
      }
    } catch (err) {
      console.error('Error fetching private messages:', err);
    }
  };

  // Gửi tin nhắn cá nhân
  const sendPrivateMessage = async (receiverId, text) => {
    try {
      const token = getToken();
      if (!token) return;

      const response = await fetch('http://localhost:3001/api/private-messages', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          receiver_id: receiverId,
          text: text
        })
      });

      if (response.ok) {
        const data = await response.json();
        // Thêm tin nhắn vào state local
        setPrivateMessages(prev => ({
          ...prev,
          [receiverId]: [...(prev[receiverId] || []), data.message_data]
        }));
      }
    } catch (err) {
      console.error('Error sending private message:', err);
    }
  };

  // Khởi tạo socket
  useEffect(() => {
    const token = getToken();
    if (!token) {
      console.error('No token found');
      return;
    }

    const newSocket = io("http://localhost:3001", {
      auth: { token },
      transports: ['websocket'], // Force WebSocket transport
      reconnection: true,
      reconnectionAttempts: 5,
      reconnectionDelay: 1000,
    });

    newSocket.on("connect", () => {
      console.log("Connected to server");
      setIsConnected(true);
    });

    newSocket.on("disconnect", (reason) => {
      console.log("Disconnected from server:", reason);
      setIsConnected(false);
      // Attempt to reconnect if not intentional
      if (reason === 'io server disconnect') {
        newSocket.connect();
      }
    });

    newSocket.on("connect_error", (error) => {
      console.error("Connection error:", error);
      setIsConnected(false);
    });

    newSocket.on("message", (msg) => {
      if (chatMode === 'public') {
        setMessages((prev) => [...prev, msg]);
      }
    });

    newSocket.on("presence", (users) => {
      setOnlineUsers(users);
    });

    // Lắng nghe tin nhắn cá nhân real-time
    newSocket.on("private_message", (data) => {
      const { conversation_id, message, sender_id, receiver_id } = data;
      const currentUserId = JSON.parse(atob(token.split('.')[1])).id;

      // Chỉ cập nhật nếu tin nhắn là cho người dùng hiện tại
      if (receiver_id === currentUserId) {
        // Sender là bạn bè gửi tin nhắn
        const friendId = sender_id;

        setPrivateMessages(prev => ({
          ...prev,
          [friendId]: [...(prev[friendId] || []), message]
        }));

        // Thêm thông báo nếu không đang chat với friend đó
        if (!selectedFriend || selectedFriend.id !== friendId) {
          const friend = friends.find(f => f.id === friendId);
          if (friend) {
            setNotifications(prev => [...prev, {
              id: `${Date.now()}-${Math.random()}`,
              type: 'private_message',
              from: friend.display_name,
              message: message.text || 'Sent an image',
              timestamp: new Date()
            }]);
          }
        }
      }
    });

    setSocket(newSocket);

    return () => {
      newSocket.disconnect();
    };
  }, [chatMode]);

  // Fetch friends once on mount
  useEffect(() => {
    if (!friendsFetchedRef.current) {
      fetchFriends();
      friendsFetchedRef.current = true;
    }
  }, []);

  // Fetch tin nhắn public khi vào chế độ public
  useEffect(() => {
    if (chatMode === 'public') {
      fetch('http://localhost:3001/api/messages')
        .then((res) => res.json())
        .then((data) => setMessages(data.messages || []))
        .catch((err) => console.error('Error fetching messages:', err));
    }
  }, [chatMode]);

  // Fetch tin nhắn private khi chọn friend
  useEffect(() => {
    if (selectedFriend && chatMode === 'private') {
      fetchPrivateMessages(selectedFriend.id);
    }
  }, [selectedFriend, chatMode]);

  const sendMessage = () => {
    if (!input.trim()) return;

    if (chatMode === 'public' && socket) {
      socket.emit("message", { text: input });
      setInput("");
    } else if (chatMode === 'private' && selectedFriend) {
      sendPrivateMessage(selectedFriend.id, input);
      setInput("");
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      sendMessage();
    }
  };

  const selectFriend = (friend) => {
    setSelectedFriend(friend);
    setChatMode('private');
  };

  const switchToPublic = () => {
    setChatMode('public');
    setSelectedFriend(null);
  };

  const currentMessages = chatMode === 'public'
    ? messages
    : (selectedFriend ? privateMessages[selectedFriend.id] || [] : []);



  // Handle image selection
  const handleImageSelect = (event) => {
    const file = event.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        setSelectedImage(e.target.result);
        sendImageMessage(e.target.result);
      };
      reader.readAsDataURL(file);
    }
  };

  // Handle camera capture
  const handleCameraCapture = (event) => {
    const file = event.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        setSelectedImage(e.target.result);
        sendImageMessage(e.target.result);
      };
      reader.readAsDataURL(file);
    }
  };

  // Send image message
  const sendImageMessage = async (imageData) => {
    if (chatMode === 'public' && socket) {
      socket.emit("message", { text: "", media_url: imageData, message_type: "image" });
    } else if (chatMode === 'private' && selectedFriend) {
      try {
        const token = getToken();
        if (!token) return;

        const response = await fetch('http://localhost:3001/api/private-messages', {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            receiver_id: selectedFriend.id,
            text: "",
            media_url: imageData,
            message_type: "image"
          })
        });

        if (response.ok) {
          const data = await response.json();
          setPrivateMessages(prev => ({
            ...prev,
            [selectedFriend.id]: [...(prev[selectedFriend.id] || []), data.message_data]
          }));
        }
      } catch (err) {
        console.error('Error sending image message:', err);
      }
    }
    setSelectedImage(null);
  };

  // Delete message
  const deleteMessage = async (messageId, isPrivate = false) => {
    try {
      const token = getToken();
      if (!token) return;

      const endpoint = isPrivate ? `http://localhost:3001/api/private-messages/${messageId}` : `http://localhost:3001/api/messages/${messageId}`;

      const response = await fetch(endpoint, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (response.ok) {
        if (isPrivate) {
          setPrivateMessages(prev => ({
            ...prev,
            [selectedFriend.id]: prev[selectedFriend.id].filter(msg => msg.id !== messageId)
          }));
        } else {
          setMessages(prev => prev.filter(msg => msg.id !== messageId));
        }
      } else {
        console.error('Error deleting message:', response.statusText);
      }
    } catch (err) {
      console.error('Error deleting message:', err);
    }
  };

  return (
    <div className="flex h-screen bg-[#f0f2f5]">
      {/* Sidebar - Conversations */}
      <div className="w-64 bg-white shadow-lg flex flex-col">
        {/* Header */}
        <div className="p-4 border-b bg-white">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-xl font-bold text-gray-900">Chats</h2>
            <button
              onClick={goBack}
              className="text-gray-500 hover:text-gray-700 text-lg"
            >
              ←
            </button>
          </div>

          {/* Search bar */}
          <div className="mb-4">
            <input
              type="text"
              placeholder="Tìm kiếm..."
              className="w-full px-3 py-2 bg-gray-100 rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>

          {/* Chat mode selector */}
          <div className="flex gap-1 mb-4">
            <button
              onClick={switchToPublic}
              className={`flex-1 py-2 px-3 rounded-lg text-sm font-medium ${
                chatMode === 'public'
                  ? 'bg-[#0084ff] text-white'
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              Chat chung
            </button>
            <button
              onClick={() => setChatMode('private')}
              className={`flex-1 py-2 px-3 rounded-lg text-sm font-medium ${
                chatMode === 'private'
                  ? 'bg-[#0084ff] text-white'
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              Nhắn tin
            </button>
          </div>
        </div>

        {/* Conversations list */}
        <div className="flex-1 overflow-y-auto">
          {chatMode === 'private' && (
            <div>
              {friends.length === 0 ? (
                <div className="text-gray-500 text-sm text-center py-8">
                  Chưa có bạn bè
                </div>
              ) : (
                friends.map((friend, index) => {
                  const isOnline = onlineUsers.some(u => u.id === friend.id);
                  const hasNotification = notifications.some(n => n.from === friend.display_name);
                  const lastMessage = privateMessages[friend.id]?.slice(-1)[0];

                  return (
                    <div
                      key={`${friend.id}-${index}`}
                      onClick={() => {
                        selectFriend(friend);
                        // Clear notifications for this friend
                        setNotifications(prev => prev.filter(n => n.from !== friend.display_name));
                      }}
                      className={`flex items-center gap-3 p-3 cursor-pointer hover:bg-gray-50 ${
                        selectedFriend?.id === friend.id ? 'bg-blue-50 border-r-4 border-[#0084ff]' : ''
                      } ${hasNotification ? 'bg-yellow-50' : ''}`}
                    >
                      <div className="relative">
                        <img
                          src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png"
                          alt="avatar"
                          className="w-12 h-12 rounded-full"
                        />
                        {isOnline && (
                          <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 border-2 border-white rounded-full"></div>
                        )}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between">
                          <div className="font-medium text-gray-900 truncate">{friend.display_name}</div>
                          {lastMessage && (
                            <div className="text-xs text-gray-500">
                              {new Date(lastMessage.created_at).toLocaleTimeString('vi-VN', {
                                hour: '2-digit',
                                minute: '2-digit'
                              })}
                            </div>
                          )}
                        </div>
                        <div className="text-sm text-gray-600 truncate">
                          {lastMessage ? (
                            lastMessage.media_url ? '📷 Hình ảnh' : lastMessage.text
                          ) : (
                            'Chưa có tin nhắn'
                          )}
                        </div>
                      </div>
                      {hasNotification && (
                        <div className="w-2 h-2 bg-red-500 rounded-full"></div>
                      )}
                    </div>
                  );
                })
              )}
            </div>
          )}

          {chatMode === 'public' && (
            <div className="p-4">
              <div className="text-center py-8">
                <div className="text-gray-500 text-sm mb-2">Chat chung</div>
                <div className="text-xs text-gray-400">{onlineUsers.length} người online</div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Chat area */}
      <div className="flex-1 flex flex-col">
        {/* Chat header */}
        <div className="bg-white shadow-sm p-4 border-b">
          <div className="flex items-center gap-3">
            {chatMode === 'private' && selectedFriend ? (
              <>
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png"
                  alt="avatar"
                  className="w-10 h-10 rounded-full"
                />
                <div>
                  <h3 className="font-semibold">{selectedFriend.display_name}</h3>
                  <p className="text-sm text-gray-500">
                    {onlineUsers.some(u => u.id === selectedFriend.id) ? 'Online' : 'Offline'}
                  </p>
                </div>
              </>
            ) : (
              <h3 className="font-semibold">Chat chung</h3>
            )}
          </div>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-4 bg-[#f0f2f5]">
          {currentMessages.map((msg, index) => {
            const isCurrentUser = msg.from?.id === currentUserId;
            const showAvatar = !isCurrentUser && (chatMode === 'private' || (chatMode === 'public' && msg.from?.id !== currentUserId));

            return (
              <div
                key={`${msg.id || 'msg'}-${index}-${Date.now()}`}
                className={`flex mb-4 ${isCurrentUser ? 'justify-end' : 'justify-start'}`}
              >
                {showAvatar && (
                  <img
                    src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png"
                    alt="avatar"
                    className="w-8 h-8 rounded-full flex-shrink-0 mr-2 self-end"
                  />
                )}
                <div className={`flex flex-col ${isCurrentUser ? 'items-end' : 'items-start'} max-w-xs lg:max-w-md`}>
                  {chatMode === 'public' && !isCurrentUser && (
                    <div className="text-xs text-gray-500 mb-1">{msg.from.display_name}</div>
                  )}
                  <div
                    className={`relative group px-3 py-2 rounded-2xl max-w-full ${
                      isCurrentUser
                        ? 'bg-[#0084ff] text-white rounded-br-md'
                        : 'bg-white text-gray-900 rounded-bl-md shadow-sm'
                    }`}
                  >
                    {msg.media_url ? (
                      <img
                        src={msg.media_url}
                        alt="Shared image"
                        className="max-w-full max-h-64 rounded-lg cursor-pointer"
                        onClick={() => window.open(msg.media_url, '_blank')}
                      />
                    ) : (
                      <div className="text-sm leading-relaxed break-words">{msg.text}</div>
                    )}
                    {isCurrentUser && msg.id && (
                      <button
                        onClick={() => deleteMessage(msg.id, chatMode === 'private')}
                        className="absolute -top-2 -right-2 text-red-500 hover:text-red-700 opacity-0 group-hover:opacity-100 transition-opacity bg-white rounded-full p-1 shadow-sm"
                        title="Xóa tin nhắn"
                      >
                        🗑️
                      </button>
                    )}
                  </div>
                  {msg.created_at && (
                    <div className="text-xs text-gray-500 mt-1">
                      {new Date(msg.created_at).toLocaleTimeString('vi-VN', {
                        hour: '2-digit',
                        minute: '2-digit'
                      })}
                    </div>
                  )}
                </div>
              </div>
            );
          })}
          <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div className="bg-white border-t p-3">
          <div className="flex gap-2 items-end">
            {/* Image upload button */}
            <button
              onClick={() => fileInputRef.current?.click()}
              className="text-gray-500 hover:text-gray-700 p-2 rounded-full hover:bg-gray-100 transition-colors"
              disabled={chatMode === 'private' && !selectedFriend}
            >
              📎
            </button>

            {/* Camera button */}
            <button
              onClick={() => cameraInputRef.current?.click()}
              className="text-gray-500 hover:text-gray-700 p-2 rounded-full hover:bg-gray-100 transition-colors"
              disabled={chatMode === 'private' && !selectedFriend}
            >
              📷
            </button>

            <div className="flex-1 relative">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder={
                  chatMode === 'private' && !selectedFriend
                    ? "Chọn bạn bè để nhắn tin..."
                    : "Nhập tin nhắn..."
                }
                disabled={chatMode === 'private' && !selectedFriend}
                className="w-full border border-gray-300 rounded-full px-4 py-2 pr-12 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>
            <button
              onClick={sendMessage}
              disabled={!input.trim() || (chatMode === 'private' && !selectedFriend)}
              className="bg-[#0084ff] text-white px-4 py-2 rounded-full hover:bg-blue-600 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
            >
              ➤
            </button>
          </div>

          {/* Hidden file inputs */}
          <input
            type="file"
            ref={fileInputRef}
            onChange={handleImageSelect}
            accept="image/*"
            style={{ display: 'none' }}
          />
          <input
            type="file"
            ref={cameraInputRef}
            onChange={handleCameraCapture}
            accept="image/*"
            capture="environment"
            style={{ display: 'none' }}
          />
        </div>
      </div>
    </div>
  );
};

export default ChatSocket;
